.darma-loader-darma-custom-227 {
  color: var(--loader-color, #0f766e);
  width: 90px;
  height: 12px;
  --c:currentColor 50%,#0000 0;
  background: 
    linear-gradient(90deg ,var(--c)) 0 0%,
    linear-gradient(-90deg,var(--c)) 0 50%,
    linear-gradient(90deg ,var(--c)) 0 100%;
  background-size: 8px calc(100%/3);
  background-repeat: repeat-x;
  animation: darma-loader-darma-custom-227-l8 .25s infinite linear;
}
@keyframes darma-loader-darma-custom-227-l8 {
    100% {background-position: -8px 0%,-8px 50%,-8px 100%}
}

